import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Optional

import torch
from peft import PeftModel
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

DEFAULT_MIN_PIXELS = 256 * 28 * 28
DEFAULT_MAX_PIXELS = 512 * 28 * 28
GRID_SIZE = 1000.0


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _has_weights(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    for name in [
        "model.safetensors",
        "model.safetensors.index.json",
        "pytorch_model.bin",
        "pytorch_model.bin.index.json",
    ]:
        if (path / name).exists():
            return True
    return False


def _read_meta(ckpt_dir: Path) -> Dict:
    meta_path = ckpt_dir / "meta.json"
    if meta_path.exists():
        try:
            return json.loads(meta_path.read_text())
        except Exception:
            return {}
    return {}


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt = Path(checkpoint).resolve()
    ckpt_dir = ckpt if ckpt.is_dir() else ckpt.parent
    meta = _read_meta(ckpt_dir)
    cwd = Path.cwd().resolve()

    candidates = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        ckpt_dir.parent.parent / "baseline" / "base_model",
        cwd / "checkpoints" / "baseline" / "base_model",
        cwd / "checkpoints" / "base_model",
        cwd / "baseline" / "base_model",
        Path("/workspace/checkpoints/baseline/base_model"),
        Path("/workspace/checkpoints/base_model"),
        Path("/workspace/baseline/base_model"),
        Path("/data/base_model/Qwen2.5-VL-3B-Instruct"),
    ]

    for key in ["base_model_dir", "base_model", "base_dir"]:
        val = meta.get(key)
        if not val:
            continue
        p = Path(val)
        if p.is_absolute():
            candidates.append(p)
        else:
            candidates.append((ckpt_dir / p).resolve())
            candidates.append((cwd / p).resolve())

    seen = set()
    ordered = []
    for p in candidates:
        s = str(p)
        if s not in seen:
            ordered.append(p)
            seen.add(s)

    for p in ordered:
        if _has_weights(p):
            return str(p)
    raise FileNotFoundError(f"Could not find packaged base model for checkpoint {checkpoint}; tried: {[str(x) for x in ordered]}")


def load_processor(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    ckpt = Path(checkpoint)
    candidates = []
    if (ckpt / "processor").exists():
        candidates.append(ckpt / "processor")
    candidates.append(ckpt)
    base = Path(resolve_base_model_dir(checkpoint))
    if (base / "processor").exists():
        candidates.append(base / "processor")
    candidates.append(base)

    last_err = None
    for cand in candidates:
        try:
            return AutoProcessor.from_pretrained(
                str(cand),
                local_files_only=True,
                trust_remote_code=False,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
            )
        except Exception as e:
            last_err = e
    raise last_err


def load_model_for_inference(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    base_dir = resolve_base_model_dir(checkpoint)
    processor = load_processor(checkpoint, min_pixels=min_pixels, max_pixels=max_pixels)
    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        torch_dtype=torch.bfloat16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    ckpt_dir = Path(checkpoint)
    if ckpt_dir.is_dir() and (ckpt_dir / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt_dir), local_files_only=True)
    model.eval()
    return model, processor


def build_messages(instruction: str):
    prompt = (
        "Locate the UI element referred to by the instruction. "
        "Return only coordinates, preferably as <point>x y</point> on a 0-1000 grid. "
        "Acceptable alternatives are <box>x1 y1 x2 y2</box>, <bbox>(x1,y1),(x2,y2)</bbox>, "
        "or plain numeric coordinates only. Do not include explanation.\n"
        f"Instruction: {instruction}"
    )
    return [
        {
            "role": "user",
            "content": [
                {"type": "image"},
                {"type": "text", "text": prompt},
            ],
        }
    ]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def clip_point(x: float, y: float, width: float, height: float) -> List[float]:
    return [max(0.0, min(float(width), float(x))), max(0.0, min(float(height), float(y)))]


def clip_bbox(x1: float, y1: float, x2: float, y2: float, width: float, height: float) -> List[float]:
    x1 = max(0.0, min(float(width), float(x1)))
    y1 = max(0.0, min(float(height), float(y1)))
    x2 = max(0.0, min(float(width), float(x2)))
    y2 = max(0.0, min(float(height), float(y2)))
    if x2 < x1:
        x1, x2 = x2, x1
    if y2 < y1:
        y1, y2 = y2, y1
    return [x1, y1, x2, y2]


def scale_point(vals: List[float], width: float, height: float) -> List[float]:
    return clip_point(vals[0] * width / GRID_SIZE, vals[1] * height / GRID_SIZE, width, height)


def scale_bbox(vals: List[float], width: float, height: float) -> List[float]:
    return clip_bbox(
        vals[0] * width / GRID_SIZE,
        vals[1] * height / GRID_SIZE,
        vals[2] * width / GRID_SIZE,
        vals[3] * height / GRID_SIZE,
        width,
        height,
    )


def parse_prediction(text: str) -> Optional[ParsedPrediction]:
    s = text.strip()

    point_tag_patterns = [
        r"<point>\s*(-?\d+(?:\.\d+)?)\s*[ ,]\s*(-?\d+(?:\.\d+)?)\s*</point>",
        r"<point[^>]*x1=[\"']?(-?\d+(?:\.\d+)?)[\"']?[^>]*y1=[\"']?(-?\d+(?:\.\d+)?)[\"']?[^>]*>",
        r"point\s*[:=]\s*\(?\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)?",
    ]
    for pat in point_tag_patterns:
        m = re.search(pat, s, flags=re.I | re.S)
        if m:
            return ParsedPrediction("point", [float(m.group(1)), float(m.group(2))], s)

    bbox_patterns = [
        r"<(?:box|bbox)>\s*(-?\d+(?:\.\d+)?)\s+[ ,]?(-?\d+(?:\.\d+)?)\s+[ ,]?(-?\d+(?:\.\d+)?)\s+[ ,]?(-?\d+(?:\.\d+)?)\s*</(?:box|bbox)>",
        r"<bbox>\s*\(?\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)?\s*,?\s*\(?\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)?\s*</bbox>",
        r"\(\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)",
    ]
    for pat in bbox_patterns:
        m = re.search(pat, s, flags=re.I | re.S)
        if m:
            return ParsedPrediction("bbox", [float(m.group(i)) for i in range(1, 5)], s)

    nums = _extract_numbers(s)
    if len(nums) >= 4:
        return ParsedPrediction("bbox", nums[:4], s)
    if len(nums) >= 2:
        return ParsedPrediction("point", nums[:2], s)
    return None


def decode_to_abs(text: str, width: float, height: float) -> Dict[str, List[float]]:
    parsed = parse_prediction(text)
    if parsed is None:
        return {"point": [width / 2.0, height / 2.0], "raw_text": text}
    if parsed.kind == "bbox":
        bbox = scale_bbox(parsed.values, width, height)
        cx = 0.5 * (bbox[0] + bbox[2])
        cy = 0.5 * (bbox[1] + bbox[3])
        return {"bbox": bbox, "point": clip_point(cx, cy, width, height), "raw_text": text}
    point = scale_point(parsed.values, width, height)
    return {"point": point, "raw_text": text}


def generate_raw(model, processor, image, instruction: str, max_new_tokens: int = 32) -> str:
    messages = build_messages(instruction)
    text = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    inputs = processor(text=[text], images=[image], padding=True, return_tensors="pt")
    inputs = {k: v.to(model.device) if hasattr(v, "to") else v for k, v in inputs.items()}
    with torch.no_grad():
        output_ids = model.generate(
            **inputs,
            max_new_tokens=max_new_tokens,
            do_sample=False,
            use_cache=True,
        )
    generated = output_ids[:, inputs["input_ids"].shape[1]:]
    text_out = processor.batch_decode(generated, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    return text_out.strip()


def generate_prediction(model, processor, image, instruction: str, width: float, height: float) -> Dict[str, List[float]]:
    raw = generate_raw(model, processor, image, instruction)
    pred = decode_to_abs(raw, width, height)
    if "point" not in pred and "bbox" in pred:
        b = pred["bbox"]
        pred["point"] = clip_point(0.5 * (b[0] + b[2]), 0.5 * (b[1] + b[3]), width, height)
    return pred
